# AUTOGENERATED! DO NOT EDIT!

def main(ads_manifest, ctx, print) -> {"job_embed_meta": dict}:
    """Embed job ad texts with per-month incremental caching."""
    from pathlib import Path
    
    import numpy as np
    import pandas as pd
    
    from ai_index.const import pipeline_store_path
    from ai_index.utils import embed
    
    run_name = ctx.vars["run_name"]
    execution_mode = ctx.vars.get("execution_mode", "api")
    embedding_model = ctx.vars["embedding_model"]
    
    store_dir = pipeline_store_path / run_name / ctx.node_name
    def _build_ad_texts(df):
        """Build role_text and task_text from job ad DataFrame columns."""
        title = df["title"].fillna("").astype(str)
        desc = df["description"].fillna("").astype(str)
        # Truncate description to 1200 chars
        desc_trunc = desc.str[:1200]
        role_text = title
        task_text = title + " - " + desc_trunc
        return role_text.tolist(), task_text.tolist()
    month_metas = []
    
    for month_info in ads_manifest["months"]:
        year = month_info["year"]
        filename = month_info["filename"]
        src_path = Path(month_info["path"])
        expected_count = month_info["row_count"]
    
        out_dir = store_dir / year
        out_path = out_dir / filename.replace(".parquet", ".npz")
    
        # Check existing cache
        existing_ids = None
        existing_role = None
        existing_task = None
        if out_path.exists():
            data = np.load(out_path, allow_pickle=True)
            existing_ids = set(data["job_ids"].tolist())
            if len(existing_ids) >= expected_count:
                print(f"embed_job_ads: {year}/{filename} — {len(existing_ids)} cached, skipping")
                month_metas.append({
                    "year": year,
                    "filename": filename,
                    "embed_path": str(out_path),
                    "row_count": len(existing_ids),
                })
                continue
            existing_role = data["role_embeddings"]
            existing_task = data["task_embeddings"]
            existing_ids_arr = data["job_ids"]
            print(f"embed_job_ads: {year}/{filename} — {len(existing_ids)} cached, need {expected_count - len(existing_ids)} more")
    
        # Read source ads
        df = pd.read_parquet(src_path)
        if existing_ids:
            # Only process missing IDs
            missing_mask = ~df["id"].astype(str).isin(existing_ids)
            df_new = df[missing_mask].reset_index(drop=True)
        else:
            df_new = df
    
        if len(df_new) == 0:
            print(f"embed_job_ads: {year}/{filename} — nothing new to embed")
            month_metas.append({
                "year": year,
                "filename": filename,
                "embed_path": str(out_path),
                "row_count": len(existing_ids) if existing_ids else 0,
            })
            continue
    
        # Build texts and embed
        role_texts, task_texts = _build_ad_texts(df_new)
        new_ids = df_new["id"].astype(str).values
    
        print(f"embed_job_ads: {year}/{filename} — embedding {len(df_new)} ads with {embedding_model} (mode={execution_mode})")
        new_role = embed(role_texts, mode=execution_mode, model=embedding_model)
        new_task = embed(task_texts, mode=execution_mode, model=embedding_model)
    
        # L2-normalize
        new_role = new_role / np.maximum(np.linalg.norm(new_role, axis=1, keepdims=True), 1e-12)
        new_task = new_task / np.maximum(np.linalg.norm(new_task, axis=1, keepdims=True), 1e-12)
    
        # Merge with existing
        if existing_role is not None:
            all_ids = np.concatenate([existing_ids_arr, new_ids])
            all_role = np.concatenate([existing_role, new_role.astype(np.float16)])
            all_task = np.concatenate([existing_task, new_task.astype(np.float16)])
        else:
            all_ids = new_ids
            all_role = new_role.astype(np.float16)
            all_task = new_task.astype(np.float16)
    
        # Save
        out_dir.mkdir(parents=True, exist_ok=True)
        np.savez(
            out_path,
            job_ids=all_ids,
            role_embeddings=all_role,
            task_embeddings=all_task,
        )
        print(f"embed_job_ads: {year}/{filename} — saved {len(all_ids)} embeddings")
    
        month_metas.append({
            "year": year,
            "filename": filename,
            "embed_path": str(out_path),
            "row_count": len(all_ids),
        })
    
    total_embedded = sum(m["row_count"] for m in month_metas)
    print(f"embed_job_ads: {total_embedded} total ads embedded across {len(month_metas)} months")
    job_embed_meta = {
        "months": month_metas,
        "embedding_model": embedding_model,
        "total_ads": total_embedded,
    }
    
    return {"job_embed_meta": job_embed_meta}
